     1	<template>
     2	  <div class="chat-bot-editor-workflow">
     3	    <el-splitter @resize="onResize">
     4	      <el-splitter-panel v-model:size="editorSize" class="chat-bot-editor-workflow__editor-wrapper">
     5	        <Editor v-model="canvasData" class="chat-bot-editor-workflow__editor-inner"/>
     6	      </el-splitter-panel>
