     9	            class="chat-bot-editor-workflow__vue-flow"
    10	            :fit-view-on-init="true"
    11	            :zoom-on-scroll="false"
    12	            @nodeDragStop="onNodeDragStop"
    13	            v-model:nodes="nodes"
    14	            v-model:edges="edges"
