    38	<script setup lang="ts">
    39	import {computed, ref, watch} from 'vue'
    40	import {VueFlow, useVueFlow} from '@vue-flow/core'
    41	import {Background} from '@vue-flow/background'
    42	import {ControlButton, Controls} from '@vue-flow/controls'
    43	import Editor from "@/components/Editor/Editor.vue";
    44	import workflowData from "./workflow.json";
    45	import HelperStorage from "@/helpers/HelperStorage";
    46	import Icon from "@/components/ChatBot/ChatBotEditorWorkflow/Icon.vue";
    47	import Node from "@/components/ChatBot/ChatBotEditorWorkflow/Node.vue";
    48	
    49	const props = defineProps<{
    50	  technicalId: string,
    51	}>();
    52	
    53	const EDITOR_WIDTH = 'chatBotEditorWorkflow:width';
    54	
    55	const canvasData = ref(JSON.stringify(workflowData, null, 2));
    56	const helperStorage = new HelperStorage();
    57	const editorSize = ref(helperStorage.get(EDITOR_WIDTH, '50%'));
    58	
    59	const {setViewport, onInit} = useVueFlow();
    60	
    61	const nodePositionKey = computed(() => {
    62	  return `workflow-node-positions${props.technicalId}`;
    63	})
    64	
    65	function loadNodePositions() {
    66	  return helperStorage.get(nodePositionKey.value, {});
    67	}
    68	
    69	function saveNodePositions(positions) {
    70	  helperStorage.set(nodePositionKey.value, positions);
    71	}
    72	
    73	let vueFlowInstance: any = null;
    74	
    75	onInit((instance) => {
    76	  vueFlowInstance = instance;
    77	})
    78	
    79	const nodes = ref([]);
    80	const edges = computed(() => {
    81	  const result = [];
    82	  let parsed;
    83	
    84	  try {
    85	    parsed = JSON.parse(canvasData.value);
    86	  } catch (e) {
    87	    console.error('Invalid JSON in canvasData:', e);
    88	    return [];
    89	  }
    90	
    91	  const states = parsed.states || {};
    92	
    93	  for (const [stateName, stateData] of Object.entries(states)) {
    94	    if (stateData.transitions) {
    95	      for (const [transitionName, transitionData] of Object.entries(stateData.transitions)) {
    96	        result.push({
    97	          id: `${stateName}-${transitionName}`,
    98	          source: stateName,
    99	          target: transitionData.next,
   100	          label: transitionName,
   101	        });
   102	      }
   103	    }
   104	  }
   105	
   106	  return result;
   107	});
   108	
   109	function generateNodes() {
   110	  const result = [];
   111	  let parsed;
   112	  const savedPositions = loadNodePositions();
   113	
   114	  try {
   115	    parsed = JSON.parse(canvasData.value);
   116	  } catch (e) {
   117	    console.error('Invalid JSON in canvasData:', e);
   118	    nodes.value = [];
   119	    return;
   120	  }
   121	
   122	  const states = parsed.states || {};
   123	  let index = 0;
   124	  const xDefault = 0;
   125	  const ySpacing = 200;
   126	
   127	  for (const [stateName, stateData] of Object.entries(states)) {
   128	    let condition = null;
   129	    let transitionNameWithCondition = null;
   130	
   131	    for (const [transitionName, transition] of Object.entries(stateData.transitions || {})) {
   132	      if (transition.condition) {
   133	        condition = transition.condition;
   134	        transitionNameWithCondition = transitionName;
   135	        break;
   136	      }
   137	    }
   138	
   139	    const position = savedPositions[stateName] || {x: xDefault, y: index * ySpacing};
   140	
   141	    result.push({
   142	      id: stateName,
   143	      type: 'default',
   144	      data: {
   145	        label: stateName,
   146	        editableCondition: condition ? JSON.stringify(condition, null, 2) : null,
   147	        stateName,
   148	        transitionName: transitionNameWithCondition,
   149	      },
   150	      position,
   151	    });
   152	    index++;
   153	  }
   154	
   155	  nodes.value = result;
   156	}
   157	
   158	generateNodes();
   159	
   160	watch(canvasData, generateNodes);
   161	
   162	function onConditionChange(event, data) {
   163	  const newCondition = event.target.value;
   164	
   165	  let parsed;
   166	  try {
   167	    parsed = JSON.parse(canvasData.value);
   168	  } catch (e) {
   169	    console.error('Invalid JSON in canvasData:', e);
   170	    return;
   171	  }
   172	
   173	  const state = parsed.states[data.stateName];
   174	  if (!state) return;
   175	
   176	  const transition = state.transitions[data.transitionName];
   177	  if (!transition) return;
   178	
   179	  try {
   180	    transition.condition = JSON.parse(newCondition);
   181	  } catch (e) {
   182	    console.error('Invalid JSON in condition textarea:', e);
   183	    return;
   184	  }
   185	
   186	  canvasData.value = JSON.stringify(parsed, null, 2);
   187	}
   188	
   189	function onNodeDragStop(event) {
   190	  const positions = loadNodePositions();
   191	
   192	  event.nodes.forEach(node => {
   193	    positions[node.id] = node.position;
   194	  });
   195	
   196	  saveNodePositions(positions);
   197	}
   198	
   199	function resetTransform() {
