   201	}
   202	
   203	function updatePos() {
   204	  nodes.value = nodes.value.map((node) => {
   205	    const newPos = {
   206	      x: Math.random() * 400,
   207	      y: Math.random() * 400,
   208	    }
   209	
   210	    return {
   211	      ...node,
   212	      position: newPos,
   213	    }
   214	  })
   215	
   216	  const positions = {};
   217	  nodes.value.forEach(node => {
   218	    positions[node.id] = node.position;
   219	  });
   220	  saveNodePositions(positions);
   221	}
   222	
   223	function onResize() {
   224	  vueFlowInstance.fitView();
   225	}
   226	
   227	watch(editorSize, (value) => {
   228	  helperStorage.set(EDITOR_WIDTH, value);
   229	})
