n  }\n  \n  return positions;\n}\n\nfunction generateNodes() {\n  const result = [];\n  let parsed;\n  const savedPositions = loadNodePositions();\n\n  try {\n    parsed = JSON.parse(canvasData.value);\n  } catch (e) {\n    console.error('Invalid JSON in canvasData:', e);\n    nodes.value = [];\n    return;\n  }\n\n  const states = parsed.states || {};\n  const initialState = parsed.initial_state;\n\n  // \u041f\u0440\u043e\u0432\u0435\u0440\u044f\u0435\u043c, \u0435\u0441\u0442\u044c \u043b\u0438 \u0441\u043e\u0445\u0440\u0430\u043d\u0435\u043d\u043d\u044b\u0435 \u043f\u043e\u0437\u0438\u0446\u0438\u0438\n  const hasSavedPositions = Object.keys(savedPositions).length > 0;\n  \n  // \u0415\u0441\u043b\u0438 \u043d\u0435\u0442 \u0441\u043e\u0445\u0440\u0430\u043d\u0435\u043d\u043d\u044b\u0445 \u043f\u043e\u0437\u0438\u0446\u0438\u0439, \u0432\u044b\u0447\u0438\u0441\u043b\u044f\u0435\u043c \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u0443\u044e \u0440\u0430\u0441\u043a\u043b\u0430\u0434\u043a\u0443\n  const autoPositions = hasSavedPositions ? {} : calculateAutoLayout(states, initialState);\n\n  for (const [stateName, stateData] of Object.entries(states)) {\n    // \u0418\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0435\u043c \u0441\u043e\u0445\u0440\u0430\u043d\u0435\u043d\u043d\u044b\u0435 \u043f\u043e\u0437\u0438\u0446\u0438\u0438 \u0438\u043b\u0438 \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u0438 \u0432\u044b\u0447\u0438\u0441\u043b\u0435\u043d\u043d\u044b\u0435\n    let position;\n\n    if (hasSavedPositions && savedPositions[stateName]) {\n      position = savedPositions[stateName];\n    } else {\n      position = autoPositions[stateName] || { x: 0, y: 0 };\n    }\n\n    const transitionCount = Object.keys(stateData.transitions || {}).length;\n    const isTerminal = transitionCount === 0;", "old_str_start_line_number": 240, "old_str_end_line_number": 274}","mcp_server_name":"","mcp_tool_name":""}},{"id":0