    49	const props = defineProps<{
    50	  technicalId: string,
    51	}>();
    52	
    53	const EDITOR_WIDTH = 'chatBotEditorWorkflow:width';
    54	
    55	const canvasData = ref(JSON.stringify(workflowData, null, 2));
    56	const helperStorage = new HelperStorage();
    57	const editorSize = ref(helperStorage.get(EDITOR_WIDTH, '50%'));
