    59	const {setViewport, onInit} = useVueFlow();
    60	
    61	const nodePositionKey = computed(() => {
    62	  return `workflow-node-positions${props.technicalId}`;
    63	})
    64	
    65	function loadNodePositions() {
    66	  return helperStorage.get(nodePositionKey.value, {});
    67	}
    68	
    69	function saveNodePositions(positions) {
    70	  helperStorage.set(nodePositionKey.value, positions);
    71	}
