   108	
   109	function generateNodes() {
   110	  const result = [];
   111	  let parsed;
   112	  const savedPositions = loadNodePositions();
   113	
   114	  try {
   115	    parsed = JSON.parse(canvasData.value);
   116	  } catch (e) {
   117	    console.error('Invalid JSON in canvasData:', e);
   118	    nodes.value = [];
   119	    return;
   120	  }
   121	
   122	  const states = parsed.states || {};
   123	  let index = 0;
   124	  const xDefault = 0;
   125	  const ySpacing = 200;
   126	
   127	  for (const [stateName, stateData] of Object.entries(states)) {
   128	    let condition = null;
   129	    let transitionNameWithCondition = null;
   130	
   131	    for (const [transitionName, transition] of Object.entries(stateData.transitions || {})) {
   132	      if (transition.condition) {
   133	        condition = transition.condition;
   134	        transitionNameWithCondition = transitionName;
   135	        break;
   136	      }
   137	    }
   138	
   139	    const position = savedPositions[stateName] || {x: xDefault, y: index * ySpacing};
   140	
   141	    result.push({
   142	      id: stateName,
   143	      type: 'default',
   144	      data: {
   145	        label: stateName,
   146	        editableCondition: condition ? JSON.stringify(condition, null, 2) : null,
   147	        stateName,
   148	        transitionName: transitionNameWithCondition,
   149	      },
   150	      position,
   151	    });
   152	    index++;
   153	  }
   154	
   155	  nodes.value = result;
   156	}
